import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ArrowLeft,
    Calendar,
    Clock,
    User,
    BookOpen,
    CreditCard,
    Tag,
    CheckCircle2,
    Circle,
    XCircle,
    AlertCircle,
    Copy,
    MessageSquare,
} from 'lucide-react';
import {
    getBookingById,
    cancelBooking,
    type BookingResponseDTO
} from '../../../services/booking.service';
import { canLeaveBookingFeedback } from '../../../services/feedback.service';
import CreateFeedbackModal from '../../ParentLessons/components/CreateFeedbackModal';
import styles from './styles.module.css';
import { message as antMessage, Spin } from 'antd';

// ===== HELPERS =====
const DAY_NAMES = ['Chủ nhật', 'Thứ 2', 'Thứ 3', 'Thứ 4', 'Thứ 5', 'Thứ 6', 'Thứ 7'];

const formatPrice = (amount: number) =>
    new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);

const formatDate = (dateStr: string) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString('vi-VN', {
        weekday: 'long',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
    });
};

const formatPackage = (pkg: string) => {
    const map: Record<string, string> = {
        '4_sessions': '4 buổi',
        '8_sessions': '8 buổi',
        '12_sessions': '12 buổi',
    };
    return map[pkg] || pkg;
};

const STATUS_CONFIG: Record<string, { label: string; className: string; icon: React.ElementType }> = {
    pending_tutor: { label: 'Chờ gia sư xác nhận', className: 'statusPending', icon: AlertCircle },
    accepted: { label: 'Chờ đặt cọc', className: 'statusWarning', icon: Clock },
    pending_payment: { label: 'Chờ thanh toán', className: 'statusWarning', icon: Clock },
    deposit_paid: { label: 'Đã cọc (50%)', className: 'statusActive', icon: CheckCircle2 },
    pending_remaining_payment: { label: 'Thanh toán khoản còn lại', className: 'statusWarning', icon: Clock },
    active: { label: 'Đang học', className: 'statusActive', icon: CheckCircle2 },
    completed: { label: 'Hoàn thành', className: 'statusCompleted', icon: CheckCircle2 },
    cancelled: { label: 'Đã hủy', className: 'statusCancelled', icon: XCircle },
    payment_timeout: { label: 'Hết hạn thanh toán', className: 'statusCancelled', icon: XCircle },
};

// Timeline steps
const TIMELINE_STEPS = [
    { key: 'created', label: 'Tạo booking' },
    { key: 'pending_tutor', label: 'Chờ gia sư' },
    { key: 'accepted', label: 'Gia sư xác nhận' },
    { key: 'deposit_paid', label: 'Đã cọc (50%)' },
    { key: 'active', label: 'Bắt đầu học' },
    { key: 'completed', label: 'Hoàn thành' },
];

const getTimelineProgress = (status: string) => {
    const progressMap: Record<string, number> = {
        pending_tutor: 2,
        accepted: 3,
        pending_payment: 3,
        deposit_paid: 4,
        pending_remaining_payment: 4,
        active: 5,
        completed: 6,
        cancelled: 0,
        payment_timeout: 0,
    };
    return progressMap[status] || 1;
};

// ===== COMPONENT =====
const BookingDetailPage = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const [booking, setBooking] = useState<BookingResponseDTO | null>(null);
    const [loading, setLoading] = useState(true);
    const [canReview, setCanReview] = useState(false);
    const [showReviewModal, setShowReviewModal] = useState(false);

    const bookingId = Number(id);

    useEffect(() => {
        const fetchBooking = async () => {
            try {
                setLoading(true);
                const res = await getBookingById(bookingId);
                setBooking(res.content);

                // Check early termination feedback eligibility
                if (['cancelled', 'completed', 'payment_timeout'].includes(res.content.status)) {
                    if (['Escrowed', 'paid', 'DepositEscrowed'].includes(res.content.paymentStatus)) {
                        const feedbackRes = await canLeaveBookingFeedback(bookingId);
                        setCanReview(feedbackRes.content);
                    }
                }
            } catch (error) {
                antMessage.error('Không thể tải chi tiết đặt lịch.');
            } finally {
                setLoading(false);
            }
        };

        if (bookingId) fetchBooking();
    }, [bookingId]);

    if (loading) {
        return (
            <div className={styles.loadingOverlay}>
                <Spin size="large" tip="Đang tải chi tiết..." />
            </div>
        );
    }

    if (!booking) {
        return (
            <div className={styles.page}>
                <div className={styles.notFound}>
                    <AlertCircle size={48} />
                    <h2>Không tìm thấy booking</h2>
                    <p>Booking #{id} không tồn tại hoặc bạn không có quyền xem.</p>
                    <button className={styles.backBtnPrimary} onClick={() => navigate('/parent/booking')} type="button">
                        Quay lại danh sách
                    </button>
                </div>
            </div>
        );
    }

    const statusCfg = STATUS_CONFIG[booking.status] || STATUS_CONFIG.pending_tutor;
    const StatusIcon = statusCfg.icon;
    const timelineProgress = getTimelineProgress(booking.status);
    const isCancelled = booking.status === 'cancelled' || booking.status === 'payment_timeout';

    return (
        <div className={styles.page}>
            {/* Top Bar */}
            <div className={styles.topBar}>
                <button className={styles.backBtn} onClick={() => navigate('/parent/booking')} type="button">
                    <ArrowLeft size={18} />
                    <span>Quay lại</span>
                </button>
                <div className={styles.topBarRight}>
                    <span className={styles.bookingCode}>
                        <Copy size={12} />
                        BK-{booking.bookingId}
                    </span>
                    <span className={`${styles.statusBadgeLg} ${styles[statusCfg.className]}`}>
                        <StatusIcon size={14} />
                        {statusCfg.label}
                    </span>
                </div>
            </div>

            {/* Main Grid */}
            <div className={styles.detailGrid}>
                {/* Left Column */}
                <div className={styles.leftColumn}>
                    {/* Tutor & Subject Card */}
                    <div className={styles.card}>
                        <div className={styles.cardHead}>
                            <BookOpen size={16} className={styles.cardHeadIcon} />
                            <h3 className={styles.cardHeadTitle}>Thông tin khóa học</h3>
                        </div>
                        <div className={styles.tutorRow}>
                            <div className={styles.tutorAvatar}>
                                {booking.tutor?.avatarUrl ? (
                                    <img src={booking.tutor.avatarUrl} alt={booking.tutor?.fullName} />
                                ) : (
                                    <span>{booking.tutor?.fullName?.charAt(0) || 'G'}</span>
                                )}
                            </div>
                            <div className={styles.tutorInfo}>
                                <h4 className={styles.tutorName}>{booking.tutor?.fullName || 'N/A'}</h4>
                                <p className={styles.tutorRate}>{formatPrice(booking.tutor?.hourlyRate || 0)}/giờ</p>
                            </div>
                        </div>
                        <div className={styles.infoGrid}>
                            <div className={styles.infoItem}>
                                <span className={styles.infoLabel}>Môn học</span>
                                <span className={styles.infoValue}>{booking.subject?.subjectName || 'N/A'}</span>
                            </div>
                            <div className={styles.infoItem}>
                                <span className={styles.infoLabel}>Gói</span>
                                <span className={styles.infoValue}>{formatPackage(booking.packageType)}</span>
                            </div>
                            <div className={styles.infoItem}>
                                <span className={styles.infoLabel}>Số buổi</span>
                                <span className={styles.infoValue}>{booking.sessionCount} buổi</span>
                            </div>
                            <div className={styles.infoItem}>
                                <span className={styles.infoLabel}>Ngày tạo</span>
                                <span className={styles.infoValue}>{formatDate(booking.createdAt)}</span>
                            </div>
                        </div>
                    </div>

                    {/* Student Card */}
                    <div className={styles.card}>
                        <div className={styles.cardHead}>
                            <User size={16} className={styles.cardHeadIcon} />
                            <h3 className={styles.cardHeadTitle}>Học sinh</h3>
                        </div>
                        <div className={styles.studentInfo}>
                            <div className={styles.studentAvatar}>
                                <span>{booking.student?.fullName?.charAt(0) || 'H'}</span>
                            </div>
                            <div>
                                <h4 className={styles.studentName}>{booking.student?.fullName || 'N/A'}</h4>
                                <p className={styles.studentGrade}>{booking.student?.gradeLevel || ''}</p>
                            </div>
                        </div>
                    </div>

                    {/* Schedule Card */}
                    <div className={styles.card}>
                        <div className={styles.cardHead}>
                            <Calendar size={16} className={styles.cardHeadIcon} />
                            <h3 className={styles.cardHeadTitle}>Lịch học</h3>
                        </div>
                        <div className={styles.scheduleList}>
                            {booking.schedule.map((s, i) => (
                                <div key={i} className={styles.scheduleItem}>
                                    <div className={styles.scheduleDayBadge}>{DAY_NAMES[s.dayOfWeek]}</div>
                                    <div className={styles.scheduleTime}>
                                        <Clock size={14} />
                                        <span>
                                            {s.startTime} — {s.endTime}
                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Right Column */}
                <div className={styles.rightColumn}>
                    {/* Price Breakdown */}
                    <div className={styles.card}>
                        <div className={styles.cardHead}>
                            <CreditCard size={16} className={styles.cardHeadIcon} />
                            <h3 className={styles.cardHeadTitle}>Chi tiết thanh toán</h3>
                        </div>
                        <div className={styles.priceBreakdown}>
                            <div className={styles.priceRow}>
                                <span>Giá gói ({formatPackage(booking.packageType)})</span>
                                <span>{formatPrice(booking.price)}</span>
                            </div>
                            {booking.discountApplied > 0 && (
                                <div className={`${styles.priceRow} ${styles.priceDiscount}`}>
                                    <span>
                                        <Tag size={12} /> Giảm giá
                                    </span>
                                    <span>-{formatPrice(booking.discountApplied)}</span>
                                </div>
                            )}
                            <div className={styles.priceDivider} />
                            <div className={`${styles.priceRow} ${styles.priceTotal}`}>
                                <span>Tổng thanh toán</span>
                                <span>{formatPrice(booking.finalPrice)}</span>
                            </div>
                            <div className={styles.priceRow + ' ' + styles.priceFee}>
                                <span>Phí nền tảng</span>
                                <span>{formatPrice(booking.platformFee)}</span>
                            </div>
                        </div>

                        {/* Payment Status */}
                        <div className={styles.paymentStatusBox}>
                            {booking.paymentStatus === 'paid' ? (
                                <>
                                    <CheckCircle2 size={18} className={styles.paymentPaid} />
                                    <span className={styles.paymentPaid}>Đã thanh toán</span>
                                </>
                            ) : (
                                <>
                                    <AlertCircle size={18} className={styles.paymentUnpaid} />
                                    <span className={styles.paymentUnpaid}>Chưa thanh toán</span>
                                </>
                            )}
                        </div>

                        {booking.paymentDueAt && (
                            <div className={styles.paymentDue}>
                                <Clock size={14} />
                                <span>Hạn thanh toán: {formatDate(booking.paymentDueAt)}</span>
                            </div>
                        )}
                    </div>

                    {/* Status Timeline */}
                    {!isCancelled && (
                        <div className={styles.card}>
                            <div className={styles.cardHead}>
                                <CheckCircle2 size={16} className={styles.cardHeadIcon} />
                                <h3 className={styles.cardHeadTitle}>Tiến trình</h3>
                            </div>
                            <div className={styles.timeline}>
                                {TIMELINE_STEPS.map((step, i) => {
                                    const isCompleted = i < timelineProgress;
                                    const isCurrent = i === timelineProgress - 1;
                                    return (
                                        <div key={step.key} className={styles.timelineStep}>
                                            <div className={styles.timelineIndicator}>
                                                {isCompleted ? (
                                                    <CheckCircle2
                                                        size={20}
                                                        className={`${styles.timelineIcon} ${styles.timelineCompleted}`}
                                                    />
                                                ) : (
                                                    <Circle size={20} className={styles.timelineIcon} />
                                                )}
                                                {i < TIMELINE_STEPS.length - 1 && (
                                                    <div
                                                        className={`${styles.timelineLine} ${isCompleted && !isCurrent ? styles.timelineLineCompleted : ''}`}
                                                    />
                                                )}
                                            </div>
                                            <span
                                                className={`${styles.timelineLabel} ${isCurrent ? styles.timelineLabelCurrent : ''} ${isCompleted && !isCurrent ? styles.timelineLabelCompleted : ''}`}
                                            >
                                                {step.label}
                                            </span>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    )}

                    {/* Cancelled notice */}
                    {isCancelled && (
                        <div className={styles.cancelledCard}>
                            <XCircle size={20} />
                            <div>
                                <h4>Booking đã bị hủy</h4>
                                <p>
                                    {booking.status === 'payment_timeout'
                                        ? 'Booking bị hủy tự động do quá hạn thanh toán 24h.'
                                        : 'Booking đã được hủy theo yêu cầu.'}
                                </p>
                            </div>
                        </div>
                    )}

                    {/* Action Buttons */}
                    <div className={styles.actionButtons}>
                        {canReview && (
                            <button
                                className={styles.payBtn}
                                style={{ background: '#4F46E5', color: 'white', marginBottom: '10px' }}
                                type="button"
                                onClick={() => setShowReviewModal(true)}
                            >
                                <MessageSquare size={16} />
                                <span>Đánh giá khóa học</span>
                            </button>
                        )}
                        {['pending_tutor', 'accepted', 'pending_payment', 'deposit_paid'].includes(booking.status) && (
                            <button
                                className={styles.cancelBtn}
                                type="button"
                                onClick={async () => {
                                    if (window.confirm('Bạn có chắc chắn muốn hủy booking này?')) {
                                        try {
                                            await cancelBooking(booking.bookingId);
                                            antMessage.success('Hủy booking thành công');
                                            // Provide immediate UI feedback by fetching updated status
                                            const res = await getBookingById(booking.bookingId);
                                            setBooking(res.content);
                                            if (['cancelled', 'completed', 'payment_timeout'].includes(res.content.status)) {
                                                if (['Escrowed', 'paid', 'DepositEscrowed'].includes(res.content.paymentStatus)) {
                                                    const feedbackRes = await canLeaveBookingFeedback(booking.bookingId);
                                                    setCanReview(feedbackRes.content);
                                                }
                                            }
                                        } catch (e) {
                                            antMessage.error('Không thể hủy booking');
                                        }
                                    }
                                }}
                            >
                                <XCircle size={16} />
                                <span>Hủy booking</span>
                            </button>
                        )}
                        {['accepted', 'pending_payment'].includes(booking.status) && (
                            <button
                                className={styles.payBtn}
                                type="button"
                                onClick={() => navigate(`/parent/booking/${booking.bookingId}/payment`)}
                            >
                                <CreditCard size={16} />
                                <span>Thanh toán cọc (50%)</span>
                            </button>
                        )}
                        {['deposit_paid', 'pending_remaining_payment'].includes(booking.status) && (
                            <button
                                className={styles.payBtn}
                                type="button"
                                onClick={() => navigate(`/parent/booking/${booking.bookingId}/payment`)}
                            >
                                <CreditCard size={16} />
                                <span>Thanh toán khoản còn lại</span>
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Feedback Modal */}
            <CreateFeedbackModal
                open={showReviewModal}
                onClose={() => setShowReviewModal(false)}
                onSuccess={() => {
                    setShowReviewModal(false);
                    setCanReview(false);
                }}
                feedbackType="early_termination"
                bookingId={booking.bookingId}
                tutorId={booking.tutor?.tutorId || ''}
                tutorName={booking.tutor?.fullName}
                subjectName={booking.subject?.subjectName}
            />
        </div>
    );
};

export default BookingDetailPage;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Calendar, Clock, User, BookOpen, Filter, ChevronLeft, ChevronRight, Plus, Eye } from 'lucide-react';
import { getParentBookings, type BookingResponseDTO } from '../../services/booking.service';
import styles from './styles.module.css';
import { message as antMessage, Spin } from 'antd';

// ===== TYPES =====

// ===== MOCK DATA REMOVED =====

// ===== HELPERS =====
const STATUS_TABS = [
  { key: 'all', label: 'Tất cả' },
  { key: 'pending_tutor', label: 'Chờ gia sư' },
  { key: 'accepted', label: 'Chờ đặt cọc' },
  { key: 'deposit_paid', label: 'Đã cọc (50%)' },
  { key: 'pending_remaining_payment', label: 'TT còn lại' },
  { key: 'active', label: 'Đang học' },
  { key: 'completed', label: 'Hoàn thành' },
  { key: 'cancelled', label: 'Đã hủy' },
];

const STATUS_CONFIG: Record<string, { label: string; className: string }> = {
  pending_tutor: { label: 'Chờ gia sư', className: 'statusPending' },
  accepted: { label: 'Chờ đặt cọc', className: 'statusWarning' },
  deposit_paid: { label: 'Đã cọc (50%)', className: 'statusActive' },
  pending_remaining_payment: { label: 'TT còn lại', className: 'statusWarning' },
  active: { label: 'Đang học', className: 'statusActive' },
  completed: { label: 'Hoàn thành', className: 'statusCompleted' },
  cancelled: { label: 'Đã hủy', className: 'statusCancelled' },
  payment_timeout: { label: 'Hết hạn TT', className: 'statusCancelled' },
};

const DAY_NAMES = ['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'];

const formatPrice = (amount: number) =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);

const formatDate = (dateStr: string) => {
  const d = new Date(dateStr);
  return d.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric' });
};

const formatPackage = (pkg: string) => {
  const map: Record<string, string> = {
    '4_sessions': '4 buổi',
    '8_sessions': '8 buổi',
    '12_sessions': '12 buổi',
  };
  return map[pkg] || pkg;
};

// ===== COMPONENT =====
const ParentBooking = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const [bookings, setBookings] = useState<BookingResponseDTO[]>([]);
  const [totalItems, setTotalItems] = useState(0);
  const [loading, setLoading] = useState(true);
  const pageSize = 5;

  const fetchBookings = async () => {
    try {
      setLoading(true);
      const res = await getParentBookings({
        status: activeTab === 'all' ? undefined : activeTab,
        page: currentPage,
        pageSize: pageSize,
      });
      setBookings(res.content.items || []);
      setTotalItems(res.content.totalCount || 0);
    } catch (error) {
      antMessage.error('Không thể tải danh sách đặt lịch.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBookings();
  }, [activeTab, currentPage]);

  const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
  const paginated = bookings;

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    setCurrentPage(1);
  };

  return (
    <div className={styles.page}>
      {/* Header */}
      <header className={styles.header}>
        <div className={styles.headerLeft}>
          <h1 className={styles.title}>My Bookings</h1>
          <p className={styles.subtitle}>Quản lý các lịch đặt gia sư của bạn</p>
        </div>
        <button className={styles.newBookingBtn} type="button">
          <Plus size={18} />
          <span>Đặt gia sư mới</span>
        </button>
      </header>

      {/* Stats Strip */}
      <div className={styles.statsStrip}>
        <div className={styles.statCard}>
          <div className={styles.statIcon + ' ' + styles.statIconBlue}>
            <BookOpen size={20} />
          </div>
          <div className={styles.statInfo}>
            <span className={styles.statValue}>{totalItems}</span>
            <span className={styles.statLabel}>Tổng bookings</span>
          </div>
        </div>
        <div className={styles.statCard}>
          <div className={styles.statIcon + ' ' + styles.statIconGreen}>
            <Calendar size={20} />
          </div>
          <div className={styles.statInfo}>
            <span className={styles.statValue}>{bookings.filter((b) => b.status === 'active').length}</span>
            <span className={styles.statLabel}>Đang học</span>
          </div>
        </div>
        <div className={styles.statCard}>
          <div className={styles.statIcon + ' ' + styles.statIconAmber}>
            <Clock size={20} />
          </div>
          <div className={styles.statInfo}>
            <span className={styles.statValue}>
              {bookings.filter((b) => b.status === 'pending_tutor' || b.status === 'pending_payment').length}
            </span>
            <span className={styles.statLabel}>Đang chờ</span>
          </div>
        </div>
      </div>

      {/* Filter Tabs */}
      <div className={styles.filterBar}>
        <Filter size={16} className={styles.filterIcon} />
        <div className={styles.tabs}>
          {STATUS_TABS.map((tab) => (
            <button
              key={tab.key}
              className={`${styles.tab} ${activeTab === tab.key ? styles.tabActive : ''}`}
              onClick={() => handleTabChange(tab.key)}
              type="button"
            >
              {tab.label}
              {tab.key !== 'all' && activeTab === tab.key && (
                <span className={styles.tabCount}>
                  {totalItems}
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Bookings List */}
      <main className={styles.mainContent}>
        {loading ? (
          <div className={styles.loadingContainer}>
            <Spin size="large" tip="Đang tải danh sách đặt lịch..." />
          </div>
        ) : paginated.length === 0 ? (
          <div className={styles.emptyState}>
            <div className={styles.emptyIcon}>
              <BookOpen size={48} />
            </div>
            <h3 className={styles.emptyTitle}>Chưa có booking nào</h3>
            <p className={styles.emptyText}>Hãy tìm gia sư phù hợp và đặt lịch học cho con bạn.</p>
            <button className={styles.emptyBtn} type="button">
              <Plus size={18} />
              <span>Đặt gia sư ngay</span>
            </button>
          </div>
        ) : (
          <>
            <div className={styles.bookingsList}>
              {paginated.map((booking) => {
                const statusCfg = STATUS_CONFIG[booking.status] || {
                  label: booking.status,
                  className: 'statusPending',
                };
                return (
                  <div
                    key={booking.bookingId}
                    className={styles.bookingCard}
                    onClick={() => navigate(`/parent/booking/${booking.bookingId}`)}
                    role="button"
                    tabIndex={0}
                    onKeyDown={(e) => e.key === 'Enter' && navigate(`/parent/booking/${booking.bookingId}`)}
                  >
                    {/* Card Header */}
                    <div className={styles.cardHeader}>
                      <div className={styles.cardHeaderLeft}>
                        <div className={styles.tutorAvatar}>
                          {booking.tutor?.avatarUrl ? (
                            <img src={booking.tutor.avatarUrl} alt={booking.tutor?.fullName} />
                          ) : (
                            <span>{booking.tutor?.fullName?.charAt(0) || 'G'}</span>
                          )}
                        </div>
                        <div className={styles.cardTitleGroup}>
                          <h3 className={styles.cardTitle}>{booking.subject?.subjectName || 'N/A'}</h3>
                          <p className={styles.cardSubtitle}>
                            với {booking.tutor?.fullName || 'Gia sư'} • cho {booking.student?.fullName || 'Học sinh'}
                          </p>
                        </div>
                      </div>
                      <span className={`${styles.statusBadge} ${styles[statusCfg.className]}`}>
                        {statusCfg.label}
                      </span>
                    </div>

                    {/* Card Body */}
                    <div className={styles.cardBody}>
                      <div className={styles.cardMeta}>
                        <div className={styles.metaItem}>
                          <BookOpen size={14} />
                          <span>{formatPackage(booking.packageType)}</span>
                        </div>
                        <div className={styles.metaItem}>
                          <Calendar size={14} />
                          <span>
                            {booking.schedule
                              .map((s) => `${DAY_NAMES[s.dayOfWeek]} ${s.startTime}-${s.endTime}`)
                              .join(', ')}
                          </span>
                        </div>
                        <div className={styles.metaItem}>
                          <User size={14} />
                          <span>
                            {booking.student?.fullName || 'N/A'} ({booking.student?.gradeLevel || ''})
                          </span>
                        </div>
                      </div>
                    </div>

                    {/* Card Footer */}
                    <div className={styles.cardFooter}>
                      <div className={styles.priceGroup}>
                        {booking.discountApplied > 0 && (
                          <span className={styles.priceOriginal}>{formatPrice(booking.price)}</span>
                        )}
                        <span className={styles.priceFinal}>{formatPrice(booking.finalPrice)}</span>
                      </div>
                      <div className={styles.cardActions}>
                        {(booking.status === 'accepted' || booking.status === 'pending_payment') && (
                          <button
                            className={styles.actionBtnPrimary}
                            onClick={(e) => {
                              e.stopPropagation();
                              navigate(`/parent/booking/${booking.bookingId}/payment`);
                            }}
                            type="button"
                          >
                            Thanh toán cọc
                          </button>
                        )}
                        {(booking.status === 'pending_remaining_payment' || booking.status === 'deposit_paid') && (
                          <button
                            className={styles.actionBtnPrimary}
                            onClick={(e) => {
                              e.stopPropagation();
                              navigate(`/parent/booking/${booking.bookingId}/payment`);
                            }}
                            type="button"
                          >
                            Thanh toán nốt
                          </button>
                        )}
                        <span className={styles.cardDate}>{formatDate(booking.createdAt)}</span>
                        <button
                          className={styles.viewBtn}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            navigate(`/parent/booking/${booking.bookingId}`);
                          }}
                        >
                          <Eye size={14} />
                          <span>Chi tiết</span>
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className={styles.pagination}>
                <button
                  className={styles.pageBtn}
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage((p) => p - 1)}
                  type="button"
                >
                  <ChevronLeft size={16} />
                </button>
                <span className={styles.pageInfo}>
                  Trang {currentPage} / {totalPages}
                </span>
                <button
                  className={styles.pageBtn}
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage((p) => p + 1)}
                  type="button"
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
};

export default ParentBooking;
